+
+    fn infer_create_table_as_select_column_infos(
+        &self,
+        select_stmt: &fsqlite_ast::SelectStatement,
+        rows: &[Row],
+    ) -> Vec<ColumnInfo> {
+        let inferred_cols = infer_select_column_names(select_stmt);
+        let col_names = if inferred_cols.is_empty() {
+            inferred_cols
+        } else {
+            let schema_ref = self.schema.borrow();
+            resolve_cte_column_names_with_schema(&inferred_cols, select_stmt, &schema_ref)
+        };
+        let width = rows.first().map_or(
+            if col_names.is_empty() {
+                1
+            } else {
+                col_names.len()
+            },
+            |row| row.values().len(),
+        );
+
+        (0..width)
+            .map(|i| {
+                let affinity = rows
+                    .iter()
+                    .map(|row| row.values().get(i).cloned().unwrap_or(SqliteValue::Null))
+                    .find(|value| !matches!(value, SqliteValue::Null))
+                    .map_or('A', |value| match value {
+                        SqliteValue::Integer(_) => 'D',
+                        SqliteValue::Float(_) => 'E',
+                        SqliteValue::Text(_) => 'B',
+                        SqliteValue::Blob(_) | SqliteValue::Null => 'A',
+                    });
+                ColumnInfo {
+                    name: col_names
+                        .get(i)
+                        .cloned()
+                        .unwrap_or_else(|| format!("_c{i}")),
+                    affinity,
+                    is_ipk: false,
+                    type_name: None,
+                    notnull: false,
+                    unique: false,
+                    default_value: None,
+                    strict_type: None,
+                    generated_expr: None,
+                    generated_stored: None,
+                    collation: None,
+                }
+            })
+            .collect()
+    }
+
+    fn execute_materialized_create_table_as_select_statement(
+        &self,
+        create: &fsqlite_ast::CreateTableStatement,
+        col_infos: Vec<ColumnInfo>,
+        rows: &[Row],
+    ) -> Result<()> {
+        let table_name = create.name.name.clone();
+
+        let schema = self.schema.borrow();
+        if schema
+            .iter()
+            .any(|table| table.name.eq_ignore_ascii_case(&table_name))
+        {
+            if create.if_not_exists {
+                return Ok(());
+            }
+            return Err(FrankenError::Internal(format!(
+                "table {table_name} already exists",
+            )));
+        }
+        drop(schema);
+
+        let width = col_infos.len();
+        let root_page = self.allocate_root_page()?;
+        self.db.borrow_mut().create_table_at(root_page, width);
+        let table_schema = TableSchema {
+            name: table_name,
+            root_page,
+            columns: col_infos,
+            indexes: Vec::new(),
+            strict: false,
+            without_rowid: false,
+            primary_key_constraints: Vec::new(),
+            foreign_keys: Vec::new(),
+            check_constraints: Vec::new(),
+        };
+        let create_sql = crate::compat_persist::build_create_table_sql(&table_schema);
+        let root_page = table_schema.root_page;
+        let table_name = table_schema.name.clone();
+        self.schema.borrow_mut().push(table_schema);
+        if !rows.is_empty() {
+            let placeholders: String = (1..=width)
+                .map(|i| format!("?{i}"))
+                .collect::<Vec<_>>()
+                .join(", ");
+            let insert_sql = format!("INSERT INTO \"{table_name}\" VALUES ({placeholders})");
+            for row in rows {
+                self.execute_with_params(&insert_sql, row.values())?;
+            }
+        }
+        self.insert_sqlite_master_row("table", &table_name, &table_name, root_page, &create_sql)?;
+        self.increment_schema_cookie()?;
+        Ok(())
+    }
